import{_ as t,o as n,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"11. Individual Flexibility Arrangements","description":"","frontmatter":{"title":"11. Individual Flexibility Arrangements","eba":"Biomedical Engineers 2025-2028","topics":["leave","annual-leave","hours","overtime"]},"headers":[],"relativePath":"ebas/biomedical-engineers/preliminary/11-individual-flexibility-arrangements.md","filePath":"ebas/biomedical-engineers/preliminary/11-individual-flexibility-arrangements.md"}'),a={name:"ebas/biomedical-engineers/preliminary/11-individual-flexibility-arrangements.md"};function i(s,e,l,p,g,d){return n(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_11-individual-flexibility-arrangements" tabindex="-1">11. Individual Flexibility Arrangements <a class="header-anchor" href="#_11-individual-flexibility-arrangements" aria-label="Permalink to &quot;11. Individual Flexibility Arrangements&quot;">​</a></h1><p><strong>11.1</strong> An Employer and Employee may agree to vary the application of the terms of this Agreement relating to any of the following in order to meet the genuine needs of both the Employee and the Employer:</p><p><strong>(a)</strong> arrangements for when work is performed;</p><p><strong>(b)</strong> overtime rates;</p><p><strong>(c)</strong> penalty rates;</p><p><strong>(d)</strong> allowances; or</p><p><strong>(e)</strong> annual leave loading.</p><p><strong>11.2</strong> An individual flexibility arrangement (IFA) must be one that is genuinely agreed to by the Employer and Employee without coercion or duress.</p><p><strong>11.3</strong> An Employer who wishes to initiate the making of an IFA must:</p><p><strong>(a)</strong> give the Employee a written proposal; and</p><p><strong>(b)</strong> if the Employer is aware that the Employee has, or reasonably should be aware that the Employee may have, limited understanding of written English, take reasonable steps (including providing a translation in an appropriate language) to ensure that the Employee understands the proposal.</p><p><strong>11.4</strong> The Employee may appoint a representative for the purposes of the procedure in this clause, including the Union. Except as provided in subclause 11.6(c), the arrangement must not require the approval or consent of a person other than the Employer and the individual Employee.</p><p><strong>11.5</strong> The Employer must ensure that the terms of the IFA:</p><p><strong>(a)</strong> are about permitted matters under section 172 of the Act; and</p><p><strong>(b)</strong> are not unlawful terms under section 194 of the Act; and</p><p><strong>(c)</strong> result in the Employee being better off overall than the Employee would be if no IFA was made.</p><p><strong>11.6</strong> The Employer must ensure that the IFA:</p><p><strong>(a)</strong> is in writing; and</p><p><strong>(b)</strong> includes the name of the Employer and Employee; and</p><p><strong>(c)</strong> is signed by the Employer and Employee and if the Employee is under 18 years of age, signed by a parent or guardian of the Employee; and</p><p><strong>(d)</strong> includes details of:</p><p><strong>(i)</strong> the terms of the enterprise agreement which will be varied and how the IFA will vary the effect of the terms; and</p><p><strong>(ii)</strong> how the Employee will be better off overall in relation to the terms and conditions of their employment as a result of the IFA; and</p><p><strong>(e)</strong> states the date on which the IFA commences.</p><p><strong>11.7</strong> The Employer must give the Employee a copy of the IFA within 14 days after it is agreed to.</p><p><strong>11.8</strong> The Employer or Employee may terminate the IFA:</p><p><strong>(a)</strong> by giving no more than 28 days written notice to the other party to the arrangement; or</p><p><strong>(b)</strong> if the Employer and Employee agree in writing — at any time.</p><p>Plain language terms: IFA, individual flex agreement.</p>',29)])])}const y=t(a,[["render",i]]);export{h as __pageData,y as default};
